    CONSTRAINT position_grade_overtime_rates_check CHECK (((hour_to IS NULL) OR (hour_to >= hour_from))),
    CONSTRAINT position_grade_overtime_rates_hour_from_check CHECK ((hour_from >= 1)),
    CONSTRAINT position_grade_overtime_rates_multiplier_check CHECK ((multiplier >= (0)::numeric))
);


--
-- Name: overtime_calculation; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.overtime_calculation AS
 WITH employee_rate_segments AS (
         SELECT otr_1.id AS overtime_request_id,
            otr_1.employee_id,
            otr_1.total_hours,
            otr_1.overtime_type,
            esh.base_salary,
            round((esh.base_salary / (173)::numeric), 2) AS hourly_rate,
            COALESCE(( SELECT jsonb_agg(jsonb_build_object('hour_from', eor.hour_from, 'hour_to', eor.hour_to, 'multiplier', eor.multiplier) ORDER BY eor.hour_from) AS jsonb_agg
                   FROM public.employee_overtime_rates eor
                  WHERE ((eor.employee_id = otr_1.employee_id) AND (eor.overtime_type = otr_1.overtime_type) AND (eor.is_active = true) AND (eor.effective_date <= otr_1.date))), ( SELECT jsonb_agg(jsonb_build_object('hour_from', pgor.hour_from, 'hour_to', pgor.hour_to, 'multiplier', pgor.multiplier) ORDER BY pgor.hour_from) AS jsonb_agg
                   FROM (public.employees e
                     JOIN public.position_grade_overtime_rates pgor ON ((pgor.position_grade_id = e.position_grade_id)))
                  WHERE ((e.id = otr_1.employee_id) AND (pgor.overtime_type = otr_1.overtime_type) AND (pgor.is_active = true) AND (pgor.effective_date <= otr_1.date))), ( SELECT jsonb_agg(jsonb_build_object('hour_from', ((rate.value ->> 'hour_from'::text))::integer, 'hour_to', ((rate.value ->> 'hour_to'::text))::integer, 'multiplier', ((rate.value ->> 'multiplier'::text))::numeric) ORDER BY ((rate.value ->> 'hour_from'::text))::integer) AS jsonb_agg
                   FROM public.companies c,
                    LATERAL jsonb_array_elements((((c.hr_settings -> 'overtime'::text) -> 'default_rates'::text) -> (otr_1.overtime_type)::text)) rate(value)
                 LIMIT 1)) AS rate_segments
           FROM (public.overtime_requests otr_1
             LEFT JOIN LATERAL ( SELECT employee_salary_histories.base_salary
                   FROM public.employee_salary_histories
                  WHERE ((employee_salary_histories.employee_id = otr_1.employee_id) AND (employee_salary_histories.effective_date <= otr_1.date))
                  ORDER BY employee_salary_histories.effective_date DESC
                 LIMIT 1) esh ON (true))
          WHERE (otr_1.status = 'approved'::public.leave_status)
        )
 SELECT ers.overtime_request_id AS id,
    ers.employee_id,
    otr.date,
    ers.total_hours,
    ers.overtime_type,
    ers.base_salary,
    ers.hourly_rate,
    ers.rate_segments,
    ( SELECT COALESCE(sum(((LEAST(GREATEST((0)::numeric, ((ers.total_hours - (((seg.value ->> 'hour_from'::text))::integer)::numeric) + (1)::numeric)),
                CASE
                    WHEN (((seg.value ->> 'hour_to'::text) IS NULL) OR ((((seg.value ->> 'hour_to'::text))::integer)::numeric >= ers.total_hours)) THEN ((ers.total_hours - (((seg.value ->> 'hour_from'::text))::integer)::numeric) + (1)::numeric)
                    ELSE (((((seg.value ->> 'hour_to'::text))::integer - ((seg.value ->> 'hour_from'::text))::integer) + 1))::numeric
                END) * ers.hourly_rate) * ((seg.value ->> 'multiplier'::text))::numeric)), (0)::numeric) AS "coalesce"
           FROM jsonb_array_elements(ers.rate_segments) seg(value)) AS overtime_pay
   FROM (employee_rate_segments ers
     JOIN public.overtime_requests otr ON ((otr.id = ers.overtime_request_id)));


