--
-- Name: v_employee_headcount; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_employee_headcount AS
 SELECT d.id AS department_id,
    d.name AS department_name,
    count(e.id) AS total_employees,
    count(e.id) FILTER (WHERE (e.employment_status = 'tetap'::public.employment_status)) AS tetap,
    count(e.id) FILTER (WHERE (e.employment_status = 'kontrak'::public.employment_status)) AS kontrak,
    count(e.id) FILTER (WHERE (e.employment_status = 'percobaan'::public.employment_status)) AS percobaan,
    count(e.id) FILTER (WHERE (e.employment_status = 'harian'::public.employment_status)) AS harian,
    count(e.id) FILTER (WHERE (e.gender = 'laki_laki'::public.gender_type)) AS laki_laki,
    count(e.id) FILTER (WHERE (e.gender = 'perempuan'::public.gender_type)) AS perempuan
   FROM (public.departments d
     LEFT JOIN public.employees e ON (((e.department_id = d.id) AND (e.deleted_at IS NULL) AND (e.is_active = true))))
  WHERE (d.deleted_at IS NULL)
  GROUP BY d.id, d.name
  ORDER BY d.name;


--
-- Name: v_leave_balance_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_leave_balance_summary AS
 SELECT e.id AS employee_id,
    e.employee_id AS nip,
    e.full_name,
    lt.name AS leave_type_name,
    lb.year,
    lb.total_quota,
    lb.used,
    lb.remaining,
    lb.rolled_over_from
   FROM ((public.employees e
     JOIN public.leave_balances lb ON ((lb.employee_id = e.id)))
     JOIN public.leave_types lt ON ((lt.id = lb.leave_type_id)))
  WHERE ((e.deleted_at IS NULL) AND (e.is_active = true))
  ORDER BY e.full_name, lt.sort_order;


--
-- Name: work_schedules; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.work_schedules (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    name character varying(255) NOT NULL,
    schedule_type public.work_schedule_type DEFAULT '5_day'::public.work_schedule_type NOT NULL,
    description text,
    monday_start time without time zone DEFAULT '08:00:00'::time without time zone NOT NULL,
    monday_end time without time zone DEFAULT '17:00:00'::time without time zone NOT NULL,
    tuesday_start time without time zone DEFAULT '08:00:00'::time without time zone NOT NULL,
    tuesday_end time without time zone DEFAULT '17:00:00'::time without time zone NOT NULL,
    wednesday_start time without time zone DEFAULT '08:00:00'::time without time zone NOT NULL,
    wednesday_end time without time zone DEFAULT '17:00:00'::time without time zone NOT NULL,
    thursday_start time without time zone DEFAULT '08:00:00'::time without time zone NOT NULL,
    thursday_end time without time zone DEFAULT '17:00:00'::time without time zone NOT NULL,
    friday_start time without time zone DEFAULT '08:00:00'::time without time zone NOT NULL,
    friday_end time without time zone DEFAULT '17:00:00'::time without time zone NOT NULL,
    saturday_start time without time zone,
    saturday_end time without time zone,
    sunday_start time without time zone,
    sunday_end time without time zone,
    break_start time without time zone DEFAULT '12:00:00'::time without time zone NOT NULL,
    break_end time without time zone DEFAULT '13:00:00'::time without time zone NOT NULL,
    late_tolerance_minutes integer DEFAULT 15 NOT NULL,
    early_leave_tolerance integer DEFAULT 15 NOT NULL,
    weekly_hours numeric(4,1) DEFAULT 40.0 NOT NULL,
    is_active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    deleted_at timestamp with time zone
);


